/**
 * Polymarket Dashboard - Unified Frontend Application
 *
 * One frontend bundle serves every site (core, watch, …); the ONLY per-site
 * artifact is site-config.js, which sets window.SITE_CONFIG (generated by
 * scripts/build_site_config.js at deploy time).
 *
 * Data is refreshed by GitHub Actions every few minutes; the JSON files land
 * in R2 and the dashboard polls metadata.json on AUTO_RELOAD_INTERVAL. When
 * metadata.snapshot is set, the big JSON files are fetched from immutable
 * per-snapshot URLs (browser-cacheable); when it is null the flat legacy
 * URLs are used with no-cache. The ↺ button forces a reload of the current
 * snapshot; the Update DB button (when present) asks the pmw-trigger worker
 * to dispatch a fresh data run.
 */

// ============================================================
// SITE CONFIG
// ============================================================

const SITE = window.SITE_CONFIG;

const DATA_BASE = SITE.dataBase;
const POLYMARKET_BASE = 'https://polymarket.com';
const REFERRAL = `?via=${SITE.polymarketReferral}`;

// Pause auto-reload after this much user inactivity.
const INACTIVITY_TIMEOUT = SITE.inactivityTimeoutMinutes * 60_000;
// Poll static JSON files more often than the data producer runs, so fresh
// data appears quickly after a scheduled refresh lands in R2.
const AUTO_RELOAD_INTERVAL = SITE.autoReloadSeconds * 1000;
const BALANCED_SHARE_DIFF_THRESHOLD = 0.10;

// Live market-price overlay. Between full data snapshots the browser polls
// Polymarket's CLOB midpoint endpoint directly for the on-screen markets and
// recomputes curPrice / entry-change% / exposure, so prices aren't stale by up
// to a snapshot interval. One batched POST per tick keeps it light on the API.
const CLOB_BASE = 'https://clob.polymarket.com';
const LIVE_PRICE_INTERVAL = 15_000;
const LIVE_PRICE_BATCH = 100;

// Cloudflare Worker that dispatches a manual data refresh via GitHub Actions.
const WORKER_URL = 'https://pmw-trigger.bobrovnikovstepan.workers.dev';

// Per-site key so the two dashboards don't fight over the saved theme.
const THEME_STORAGE_KEY = `${SITE.siteId}-theme`;

// State
let metadata = null;
let traderPortfolios = null;
let aggregatedPortfolio = null;
let recentChanges = null;
let lastActivityTime = Date.now();
let autoReloadTimer = null;
let lastUpdatedTicker = null;
let updatePollTimer = null;
let livePriceTimer = null;

// Concurrency guard: loadData() no-ops while a load is already in flight.
let isLoading = false;
// Snapshot id of the currently rendered data. When metadata.snapshot matches,
// the big files are unchanged and re-fetching them is skipped entirely.
let loadedSnapshot = null;

// Portfolio sort state. `mode` is 'abs' or 'rel' and only applies to change columns.
let portfolioSort = { column: 'totalExposure', direction: 'desc', mode: 'abs' };
let hideBalancedPairs = false;
// Markets from the same Polymarket event are grouped into one section in the
// Portfolio table, with events ranked by their biggest single market (so the
// overall size sort is preserved).
// Event-stack display mode, cycled by the stack toggle button:
//   'off'      — no stacking
//   'expanded' — stacked, sections open by default
//   'folded'   — stacked, sections collapsed by default
let stackEvents = 'off';
// Per-section exceptions to the current default fold state (keyed as in
// renderStackedEvents). A key here means "the opposite of the mode default":
// in 'expanded' mode it's a folded section, in 'folded' mode an opened one.
// Cleared whenever the global mode changes; persists across re-renders so
// live-price refreshes keep the user's per-section choices.
const eventStackOverrides = new Set();
// True when a section should render collapsed, combining the global default
// (from the mode) with any per-section override.
function isEventStackCollapsed(key) {
  const defaultCollapsed = stackEvents === 'folded';
  return eventStackOverrides.has(key) ? !defaultCollapsed : defaultCollapsed;
}
// Odds-range filter on the Portfolio table. Upper bound as a price fraction
// (current market odds): 1.0 = 0–100c = show everything (default). When set
// lower, an event is kept only if ANY of its outcomes' current odds are at or
// below the bound — and both YES and NO sides of every kept event stay visible.
let oddsFilterMax = 1.0;

// Recent Changes "Aggregate" toggle: when true, the changes-table is replaced
// with a portfolio-style aggregate of just the positions that match the active
// size + time filters.
let changesAggregateMode = false;

// Recent Changes "event filter": when set to a conditionId, the Recent Changes
// view is scoped to a single market. It is only set via the ↗ arrow in the
// Portfolio table's "Recent changes" column and cleared with the Clear filters
// button. In this mode the Aggregate toggle collapses activity per trader.
let changesEventFilter = null;

// DOM Elements
const tabs = document.querySelectorAll('.tab');
const sections = document.querySelectorAll('.section');

// ============================================================
// SITE CHROME
// ============================================================

/**
 * Apply per-site branding from SITE_CONFIG: page title, header, traders
 * column label, GitHub link, and the Cloudflare analytics beacon (which used
 * to live inline in each site's index.html).
 */
function applySiteChrome() {
  document.title = SITE.pageTitle;

  const siteTitle = document.getElementById('site-title');
  if (siteTitle) siteTitle.textContent = SITE.siteName;

  document.querySelectorAll('#traders-column-label, .traders-column-label').forEach(el => {
    el.textContent = SITE.tradersColumnLabel;
  });

  const githubLink = document.getElementById('github-link');
  if (githubLink) githubLink.href = SITE.githubUrl;

  if (SITE.analyticsToken) {
    const beacon = document.createElement('script');
    beacon.defer = true;
    beacon.src = 'https://static.cloudflareinsights.com/beacon.min.js';
    beacon.setAttribute('data-cf-beacon', JSON.stringify({ token: SITE.analyticsToken }));
    document.head.appendChild(beacon);
  }
}

// ============================================================
// API HELPERS
// ============================================================

/**
 * Fetch one of the big JSON files for a given snapshot.
 *
 * With a snapshot id, the URL is immutable (each data run gets its own
 * prefix) so the browser's default caching is exactly right. Without one
 * (older deploys), fall back to the flat URL and bypass the HTTP cache.
 */
async function fetchSnapshotJSON(filename, snapshot) {
  const url = snapshot ? `${DATA_BASE}/${snapshot}/${filename}` : `${DATA_BASE}/${filename}`;
  const response = await fetch(url, snapshot ? undefined : { cache: 'no-cache' });
  if (!response.ok) {
    throw new Error(`Failed to fetch ${filename}`);
  }
  return response.json();
}

// ============================================================
// FORMAT HELPERS
// ============================================================

/**
 * Format currency
 */
function formatUSD(value) {
  const num = parseFloat(value) || 0;
  if (Math.abs(num) >= 1000000) {
    return '$' + (num / 1000000).toFixed(2) + 'M';
  }
  if (Math.abs(num) >= 1000) {
    return '$' + (num / 1000).toFixed(1) + 'K';
  }
  return '$' + num.toFixed(2);
}

function formatShares(value) {
  const num = Math.abs(parseFloat(value) || 0);
  if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
  if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
  if (num >= 100) return num.toFixed(0);
  return num.toFixed(2).replace(/\.?0+$/, '');
}

function getPositionShares(position) {
  if (Number.isFinite(position?.totalSize)) return Math.abs(position.totalSize);
  return (position?.traders || []).reduce((sum, trader) => sum + Math.abs(parseFloat(trader.size || 0)), 0);
}

function getBinaryOutcomeSide(position) {
  const outcome = String(position?.outcome || '').trim().toLowerCase();
  if (outcome === 'yes') return 'yes';
  if (outcome === 'no') return 'no';
  return null;
}

function getNearBalancedConditionIds(positions) {
  const sharesByMarket = new Map();

  for (const position of positions || []) {
    const side = getBinaryOutcomeSide(position);
    if (!side || !position?.conditionId) continue;

    const shares = getPositionShares(position);
    if (!Number.isFinite(shares) || shares <= 0) continue;

    if (!sharesByMarket.has(position.conditionId)) {
      sharesByMarket.set(position.conditionId, { yes: 0, no: 0 });
    }
    sharesByMarket.get(position.conditionId)[side] += shares;
  }

  const balanced = new Set();
  for (const [conditionId, sides] of sharesByMarket) {
    const largerSide = Math.max(sides.yes, sides.no);
    if (sides.yes <= 0 || sides.no <= 0 || largerSide <= 0) continue;

    const shareDiffPct = Math.abs(sides.yes - sides.no) / largerSide;
    if (shareDiffPct < BALANCED_SHARE_DIFF_THRESHOLD) {
      balanced.add(conditionId);
    }
  }

  return balanced;
}

function filterBalancedPositions(positions) {
  if (!hideBalancedPairs || !positions?.length) return positions || [];
  const balancedConditionIds = getNearBalancedConditionIds(positions);
  return positions.filter(position => !balancedConditionIds.has(position.conditionId));
}

/**
 * Current market odds of a position as a 0–1 price fraction. Uses the live
 * midpoint (`curPrice`); falls back to the average entry price when the
 * midpoint is missing. Returns null when neither is available.
 */
function getPositionOdds(position) {
  const cur = parseFloat(position?.curPrice);
  if (Number.isFinite(cur)) return cur;
  const entry = parseFloat(position?.avgEntry);
  return Number.isFinite(entry) ? entry : null;
}

/**
 * Keep only events that have at least one outcome whose current odds fall in
 * the selected 0–Xc range. Both YES and NO sides of each matching event are
 * retained; events entirely outside the range are dropped. At the default
 * 0–100c bound nothing is filtered.
 */
function filterByOddsRange(positions) {
  if (oddsFilterMax >= 1 || !positions?.length) return positions || [];
  const passing = new Set();
  for (const position of positions) {
    if (!position?.conditionId) continue;
    const odds = getPositionOdds(position);
    if (odds != null && odds <= oddsFilterMax + 1e-9) passing.add(position.conditionId);
  }
  // Positions without a conditionId can't be grouped into an event — keep them.
  return positions.filter(p => !p.conditionId || passing.has(p.conditionId));
}

function formatExposureWithShares(exposure, shares) {
  const shareCount = Math.abs(parseFloat(shares) || 0);
  return shareCount > 0
    ? `${formatUSD(exposure)} / ${formatShares(shareCount)} shares`
    : formatUSD(exposure);
}

/**
 * Format price as cents
 */
function formatCents(value) {
  const num = parseFloat(value) || 0;
  return Math.round(num * 100) + 'c';
}

/**
 * Format relative time
 */
function formatRelativeTime(timestamp) {
  const now = Date.now() / 1000;
  const diff = now - timestamp;
  if (diff < 60) return 'just now';
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
}

/**
 * Format date as "04 Jan 2026"
 */
function formatExpirationDate(dateStr) {
  if (!dateStr) return '-';
  try {
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return '-';
    const day = date.getDate().toString().padStart(2, '0');
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const month = months[date.getMonth()];
    const year = date.getFullYear();
    return `${day} ${month} ${year}`;
  } catch {
    return '-';
  }
}

/**
 * Parse date string to timestamp for sorting
 */
function parseExpirationDate(dateStr) {
  if (!dateStr) return 0;
  try {
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? 0 : date.getTime();
  } catch {
    return 0;
  }
}

/**
 * Truncate address
 */
function truncateAddress(address) {
  if (!address) return '';
  return address.slice(0, 6) + '...' + address.slice(-4);
}

/**
 * Copy to clipboard
 */
async function copyToClipboard(text) {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch {
    return false;
  }
}

/**
 * Build Polymarket URL with referral
 */
function polymarketUrl(path) {
  return `${POLYMARKET_BASE}${path}${REFERRAL}`;
}

// ============================================================
// AUTO-RELOAD
// ============================================================

/**
 * Auto-reload JSON files on AUTO_RELOAD_INTERVAL; tick the "Xm ago"
 * timestamp display every 30s so it stays current between reloads.
 * The ticker is created only once, no matter how often this is called.
 */
function startAutoReload() {
  if (autoReloadTimer) clearInterval(autoReloadTimer);
  autoReloadTimer = setInterval(async () => {
    // Pause if user has been inactive longer than INACTIVITY_TIMEOUT
    if (Date.now() - lastActivityTime > INACTIVITY_TIMEOUT) return;
    await loadData();
  }, AUTO_RELOAD_INTERVAL);

  if (!lastUpdatedTicker) {
    lastUpdatedTicker = setInterval(updateLastUpdated, 30_000);
  }
}

// ============================================================
// LIVE PRICE OVERLAY
// ============================================================

/**
 * Unique CLOB token ids for the positions currently in the aggregated
 * portfolio. Positions from older snapshots that predate the `asset` field are
 * skipped (no token id to query) — the overlay simply no-ops until fresh data.
 */
function collectPositionTokens() {
  const tokens = new Set();
  for (const p of aggregatedPortfolio?.positions || []) {
    if (p.asset) tokens.add(p.asset);
  }
  return [...tokens];
}

/**
 * Batch-fetch current midpoint prices for the given CLOB token ids.
 * Returns a Map token_id → mid (number > 0). Any network/parse failure yields
 * an empty (or partial) map, so the overlay keeps the last-known prices.
 */
async function fetchLiveMidpoints(tokenIds) {
  const out = new Map();
  for (let i = 0; i < tokenIds.length; i += LIVE_PRICE_BATCH) {
    const chunk = tokenIds.slice(i, i + LIVE_PRICE_BATCH);
    try {
      const res = await fetch(`${CLOB_BASE}/midpoints`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(chunk.map(token_id => ({ token_id })))
      });
      if (!res.ok) continue;
      const data = await res.json();
      for (const [token, mid] of Object.entries(data || {})) {
        const v = parseFloat(mid);
        if (Number.isFinite(v) && v > 0) out.set(token, v);
      }
    } catch (_) { /* keep prior prices on failure */ }
  }
  return out;
}

/**
 * Apply fresh midpoints onto the in-memory aggregated portfolio: update each
 * position's curPrice, its entry change %, and its market exposure
 * (shares × live price, matching the server's size×curPrice exposure).
 * Returns true if any position moved.
 */
function applyLiveMidpoints(midByToken) {
  if (!midByToken.size || !aggregatedPortfolio?.positions) return false;
  let changed = false;
  for (const p of aggregatedPortfolio.positions) {
    const mid = p.asset ? midByToken.get(p.asset) : undefined;
    if (mid === undefined || mid === p.curPrice) continue;
    p.curPrice = mid;
    p.priceChangePct = p.avgEntry > 0
      ? Math.round(((mid - p.avgEntry) / p.avgEntry) * 1000) / 10
      : p.priceChangePct;
    p.totalExposure = getPositionShares(p) * mid;
    changed = true;
  }
  if (changed) rescalePortfolioSummary();
  return changed;
}

/**
 * Keep the summary cards consistent with live exposures. totalExposure is the
 * exact sum; relativeExposure tracks it proportionally (invested capital
 * doesn't change on a price tick). Concentration ratios barely move tick-to-
 * tick and use the server's market-grouped method, so they're left as-is.
 */
function rescalePortfolioSummary() {
  const s = aggregatedPortfolio?.summary;
  const positions = aggregatedPortfolio?.positions;
  if (!s || !positions) return;
  const prevTotal = s.totalExposure || 0;
  const newTotal = positions.reduce((sum, p) => sum + (p.totalExposure || 0), 0);
  if (prevTotal > 0) s.relativeExposure = s.relativeExposure * (newTotal / prevTotal);
  s.totalExposure = newTotal;
}

/**
 * One overlay tick: pull live midpoints for the on-screen markets and, if any
 * moved, re-render the portfolio table + summary. Paused while the user is
 * inactive or the tab is hidden so idle tabs make no requests.
 */
async function refreshLivePrices() {
  if (Date.now() - lastActivityTime > INACTIVITY_TIMEOUT) return;
  if (document.hidden) return;
  const tokens = collectPositionTokens();
  if (!tokens.length) return;
  const mids = await fetchLiveMidpoints(tokens);
  if (applyLiveMidpoints(mids)) {
    renderPortfolioSummary();
    renderPortfolioTable();
  }
}

function startLivePrices() {
  if (livePriceTimer) clearInterval(livePriceTimer);
  livePriceTimer = setInterval(refreshLivePrices, LIVE_PRICE_INTERVAL);
}

// ============================================================
// UI UPDATE FUNCTIONS
// ============================================================

/**
 * Update last updated display
 */
function updateLastUpdated() {
  const el = document.getElementById('last-updated');
  const timestampEl = el?.querySelector('.timestamp');
  const statusDot = el?.querySelector('.status-dot');

  if (!metadata?.last_updated) {
    if (timestampEl) timestampEl.textContent = 'No data';
    statusDot?.classList.add('stale');
    return;
  }

  const updated = new Date(metadata.last_updated);
  const diffMinutes = (Date.now() - updated) / 60000;

  if (timestampEl) {
    timestampEl.textContent = `Updated ${formatRelativeTime(updated.getTime() / 1000)}`;
  }

  if (diffMinutes > 30) {
    statusDot?.classList.add('stale');
  } else {
    statusDot?.classList.remove('stale');
  }
}

function updateTrackedTradersTitle() {
  const title = document.getElementById('tracked-traders-title');
  if (!title) return;

  const count = metadata?.trader_count ?? (traderPortfolios ? Object.keys(traderPortfolios).length : null);
  title.textContent = count ? `Tracked Traders (${count})` : 'Tracked Traders';
}

/**
 * Canary trap: splice this viewer's injected honeytoken trader into the list ONLY.
 * The wallet arrives as `window.__CANARY` from the gate (unique per user). It is
 * display-only — the aggregates are precomputed server-side and never include it —
 * so it shows up among the tracked traders but touches no calculation. Never throws.
 */
function mergeCanary() {
  try {
    const c = window.__CANARY;
    if (!c || !c.address || !traderPortfolios) return;
    const addr = c.address.toLowerCase();
    if (traderPortfolios[addr]) return;                 // never shadow a real trader
    traderPortfolios[addr] = {
      address: addr,
      label: c.label || 'Unknown',
      totalValue: c.totalValue || 0,
      usdcBalance: c.usdcBalance || 0,
      totalPnL: c.totalPnL || 0,
      positions: Array.from({ length: c.positionCount || 0 }, () => ({})),
      canary: true,
      fetchSuccess: false,
    };
    if (metadata && typeof metadata.trader_count === 'number') metadata.trader_count += 1;
  } catch (e) { /* the canary must never break the dashboard */ }
}

/**
 * Render traders table
 */
function renderTradersTable(searchTerm = '') {
  const tbody = document.getElementById('traders-tbody');
  if (!traderPortfolios) {
    tbody.innerHTML = '<tr><td colspan="7" class="loading">Loading...</td></tr>';
    return;
  }

  const traders = Object.values(traderPortfolios)
    .filter(t => {
      if (!searchTerm) return true;
      const term = searchTerm.toLowerCase();
      return t.label?.toLowerCase().includes(term) ||
             t.address?.toLowerCase().includes(term);
    })
    .sort((a, b) => (b.totalValue || 0) - (a.totalValue || 0));

  if (traders.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" class="loading">No traders found</td></tr>';
    return;
  }

  tbody.innerHTML = traders.map((trader, idx) => {
    const pnlClass = (trader.totalPnL || 0) >= 0 ? 'positive' : 'negative';
    const pnlSign = (trader.totalPnL || 0) >= 0 ? '+' : '';

    return `
      <tr>
        <td>${idx + 1}</td>
        <td>
          <div class="trader-cell">
            <div class="trader-avatar">${trader.label?.charAt(0) || '?'}</div>
            <div>
              <a href="${polymarketUrl('/profile/' + trader.address)}" target="_blank" class="trader-label">${trader.label || 'Unknown'}</a>
              <div class="trader-address">${truncateAddress(trader.address)}</div>
            </div>
          </div>
        </td>
        <td>${formatUSD(trader.totalValue)}</td>
        <td>${formatUSD(trader.usdcBalance || 0)}</td>
        <td class="${pnlClass}">${pnlSign}${formatUSD(trader.totalPnL || 0)}</td>
        <td>${trader.positions?.length || 0}</td>
        <td>
          <button class="btn btn-copy" onclick="copyToClipboard('${trader.address}').then(() => this.textContent = 'Copied!').finally(() => setTimeout(() => this.textContent = 'Copy', 1500))">
            Copy
          </button>
        </td>
      </tr>
    `;
  }).join('');
}

/**
 * Render portfolio summary
 */
function renderPortfolioSummary() {
  if (!aggregatedPortfolio?.summary) return;

  const s = aggregatedPortfolio.summary;
  document.getElementById('total-exposure').textContent = formatUSD(s.totalExposure);
  document.getElementById('relative-exposure').textContent = s.relativeExposure.toFixed(1) + '%';
  document.getElementById('distinct-markets').textContent = s.distinctMarkets;
  document.getElementById('top1-share').textContent = (s.top1Share * 100).toFixed(1) + '%';
  document.getElementById('top5-share').textContent = (s.top5Share * 100).toFixed(1) + '%';

  const flow24h = document.getElementById('net-flow-24h');
  flow24h.textContent = formatUSD(s.netFlow24h);
  flow24h.className = 'card-value ' + (s.netFlow24h >= 0 ? 'positive' : 'negative');
}

/**
 * Group positions by conditionId to combine YES/NO outcomes
 */
function groupPositionsByMarket(positions) {
  const grouped = new Map();

  for (const pos of positions) {
    const key = pos.conditionId;
    if (!grouped.has(key)) {
      grouped.set(key, {
        conditionId: pos.conditionId,
        title: pos.title,
        slug: pos.slug,
        icon: pos.icon,
        eventSlug: pos.eventSlug,
        endDate: pos.endDate,
        outcomes: []
      });
    }
    grouped.get(key).outcomes.push(pos);
  }

  // Calculate combined metrics for sorting
  for (const [key, market] of grouped) {
    market.totalExposure = market.outcomes.reduce((sum, o) => sum + (o.totalExposure || 0), 0);
    market.traderCount = market.outcomes.reduce((max, o) => Math.max(max, o.traderCount || 0), 0);
    market._change1h = market.outcomes.reduce((sum, o) => sum + (o._change1h || 0), 0);
    market._change1d = market.outcomes.reduce((sum, o) => sum + (o._change1d || 0), 0);
    market._change1w = market.outcomes.reduce((sum, o) => sum + (o._change1w || 0), 0);

    // Sort outcomes: Yes first, then No
    market.outcomes.sort((a, b) => {
      if (a.outcome === 'Yes' && b.outcome !== 'Yes') return -1;
      if (a.outcome !== 'Yes' && b.outcome === 'Yes') return 1;
      return 0;
    });
  }

  return Array.from(grouped.values());
}

/**
 * Sort positions for portfolio table
 */
function sortPositions(positions) {
  const sorted = [...positions].sort((a, b) => {
    let aVal, bVal;
    switch (portfolioSort.column) {
      case 'traderCount':
        aVal = a.traderCount || 0;
        bVal = b.traderCount || 0;
        break;
      case 'totalExposure':
        aVal = a.totalExposure || 0;
        bVal = b.totalExposure || 0;
        break;
      case 'change1h':
        aVal = portfolioSort.mode === 'rel' ? (a._change1hPct ?? 0) : (a._change1h || 0);
        bVal = portfolioSort.mode === 'rel' ? (b._change1hPct ?? 0) : (b._change1h || 0);
        break;
      case 'change1d':
        aVal = portfolioSort.mode === 'rel' ? (a._change1dPct ?? 0) : (a._change1d || 0);
        bVal = portfolioSort.mode === 'rel' ? (b._change1dPct ?? 0) : (b._change1d || 0);
        break;
      case 'change1w':
        aVal = portfolioSort.mode === 'rel' ? (a._change1wPct ?? 0) : (a._change1w || 0);
        bVal = portfolioSort.mode === 'rel' ? (b._change1wPct ?? 0) : (b._change1w || 0);
        break;
      case 'endDate':
        aVal = parseExpirationDate(a.endDate);
        bVal = parseExpirationDate(b.endDate);
        break;
      case 'title':
        aVal = a.title || '';
        bVal = b.title || '';
        return portfolioSort.direction === 'asc'
          ? aVal.localeCompare(bVal)
          : bVal.localeCompare(aVal);
      default:
        aVal = a.totalExposure || 0;
        bVal = b.totalExposure || 0;
    }
    return portfolioSort.direction === 'asc' ? aVal - bVal : bVal - aVal;
  });
  return sorted;
}

/**
 * Handle portfolio column sort click.
 * For change columns, cycles abs▼ → rel▼ → abs▲ → rel▲ → abs▼ on repeated clicks.
 * For other columns, toggles direction as before.
 */
function handlePortfolioSort(column) {
  const isChangeColumn = column === 'change1h' || column === 'change1d' || column === 'change1w';
  if (portfolioSort.column !== column) {
    portfolioSort.column = column;
    portfolioSort.direction = 'desc';
    portfolioSort.mode = 'abs';
  } else if (isChangeColumn) {
    if (portfolioSort.mode === 'abs' && portfolioSort.direction === 'desc') {
      portfolioSort.mode = 'rel'; // → rel desc
    } else if (portfolioSort.mode === 'rel' && portfolioSort.direction === 'desc') {
      portfolioSort.mode = 'abs'; portfolioSort.direction = 'asc'; // → abs asc
    } else if (portfolioSort.mode === 'abs' && portfolioSort.direction === 'asc') {
      portfolioSort.mode = 'rel'; // → rel asc
    } else {
      portfolioSort.mode = 'abs'; portfolioSort.direction = 'desc'; // cycle back
    }
  } else {
    portfolioSort.direction = portfolioSort.direction === 'asc' ? 'desc' : 'asc';
  }
  renderPortfolioTable();
  // Mirror sort changes into the aggregate-changes view if it's active.
  if (changesAggregateMode) {
    const dF = parseInt(document.getElementById('delta-filter')?.value || 0);
    const tF = document.getElementById('time-filter')?.value || 'all';
    renderChangesTable(dF, tF);
  }
}

function handleAggregateToggle() {
  changesAggregateMode = !changesAggregateMode;
  const btn = document.getElementById('aggregate-toggle');
  if (btn) btn.classList.toggle('active', changesAggregateMode);
  const dF = parseInt(document.getElementById('delta-filter')?.value || 0);
  const tF = document.getElementById('time-filter')?.value || 'all';
  renderChangesTable(dF, tF);
}

/**
 * Resolve a human-readable market title for a conditionId from whatever data
 * we have loaded (portfolio positions first, then the raw changes feed).
 */
function getMarketTitle(conditionId) {
  if (!conditionId) return 'Selected market';
  const pos = (aggregatedPortfolio?.positions || []).find(p => p.conditionId === conditionId);
  if (pos?.title) return pos.title;
  const change = (recentChanges?.changes || []).find(c => c.conditionId === conditionId);
  return change?.market || 'Selected market';
}

/**
 * Jump from the Portfolio table to the Recent Changes tab, scoped to a single
 * market. Resets the size/time filters so every trader buying or selling this
 * market is visible.
 */
function showEventChanges(conditionId) {
  if (!conditionId) return;
  changesEventFilter = conditionId;

  const deltaFilter = document.getElementById('delta-filter');
  const timeFilter = document.getElementById('time-filter');
  if (deltaFilter) deltaFilter.value = '0';
  if (timeFilter) timeFilter.value = 'all';

  switchTab('changes');
  updateEventFilterBar();
  renderChangesTable(0, 'all');
  document.getElementById('changes-section')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

/**
 * Clear the per-market event filter and return to the standard Recent Changes
 * list across all markets.
 */
function clearEventFilter() {
  changesEventFilter = null;
  updateEventFilterBar();
  const dF = parseInt(document.getElementById('delta-filter')?.value || 0);
  const tF = document.getElementById('time-filter')?.value || 'all';
  renderChangesTable(dF, tF);
}

/**
 * Show/hide the "Showing recent changes for: …" bar above the changes table.
 */
function updateEventFilterBar() {
  const bar = document.getElementById('event-filter-bar');
  const nameEl = document.getElementById('event-filter-name');
  if (!bar) return;
  if (changesEventFilter) {
    if (nameEl) nameEl.textContent = getMarketTitle(changesEventFilter);
    bar.style.display = 'flex';
  } else {
    bar.style.display = 'none';
  }
}

/**
 * Get sort indicator. For change columns in 'rel' mode, append "%".
 */
function getSortIndicator(column) {
  if (portfolioSort.column !== column) return '';
  const arrow = portfolioSort.direction === 'asc' ? ' ▲' : ' ▼';
  const isChangeColumn = column === 'change1h' || column === 'change1d' || column === 'change1w';
  if (isChangeColumn && portfolioSort.mode === 'rel') return `${arrow}%`;
  return arrow;
}

/**
 * Build 24h change tooltip content showing activities that contributed to the change
 */
function build24hTooltip(pos) {
  if (!recentChanges?.changes) return '';

  // Find activities in last 24h for this position
  const now = Date.now() / 1000;
  const cutoff24h = now - 24 * 3600;

  const activities = recentChanges.changes.filter(c => {
    return c.conditionId === pos.conditionId &&
           c.outcomeIndex === pos.outcomeIndex &&
           c.timestamp >= cutoff24h;
  });

  if (activities.length === 0) {
    // No activities, change might be from price movement
    if (pos.priceChangePct && Math.abs(pos.priceChangePct) > 0.1) {
      return `Price change: ${pos.priceChangePct >= 0 ? '+' : ''}${pos.priceChangePct.toFixed(1)}%`;
    }
    return '';
  }

  const lines = activities
    .slice(0, 5)
    .map(a => {
      const action = a.action === 'increased' ? 'bought' : 'sold';
      return `${a.trader} ${action} ${formatUSD(Math.abs(a.delta))}`;
    });

  if (activities.length > 5) {
    lines.push(`+${activities.length - 5} more trades...`);
  }

  return lines.join('<br>');
}

/**
 * Render a single outcome row for the portfolio table
 */
function renderOutcomeRow(outcome, totalExposure, isFirst, rowSpanCount, marketInfo) {
  const outcomeClass = outcome.outcome === 'Yes' ? 'outcome-yes' : 'outcome-no';

  // Format entry price with change %
  let entryHtml = '-';
  if (outcome.avgEntry > 0) {
    const changePct = outcome.priceChangePct || 0;
    const changeClass = changePct >= 0 ? 'positive' : 'negative';
    const changeSign = changePct >= 0 ? '+' : '';
    entryHtml = `
      <div class="entry-price">
        <span class="entry-main">${formatCents(outcome.avgEntry)}</span>
        <span class="entry-change ${changeClass}">(${changeSign}${changePct.toFixed(1)}%)</span>
      </div>
    `;
  }

  // Format trader count with the 24h entered/exited counter, e.g. "6 (+2/−1)"
  const flow = outcome.traderFlow24h;
  let traderCountHtml = `${outcome.traderCount}`;
  if (flow && (flow.entered || flow.exited)) {
    const parts = [];
    if (flow.entered) parts.push(`<span class="positive">+${flow.entered}</span>`);
    if (flow.exited) parts.push(`<span class="negative">&minus;${flow.exited}</span>`);
    traderCountHtml = `${outcome.traderCount} <span class="trader-flow">(${parts.join('/')})</span>`;
  }

  // Calculate allocation % for this outcome
  const allocPct = totalExposure > 0 ? (outcome.totalExposure / totalExposure) * 100 : 0;

  // Get changes for this specific outcome
  const changes = calculatePositionChanges(outcome.conditionId, outcome.outcomeIndex);
  outcome._change1h = changes.h1;
  outcome._change1d = changes.d1;
  outcome._change1w = changes.w1;

  const h1Class = changes.h1 >= 0 ? 'positive' : 'negative';
  const d1Class = changes.d1 >= 0 ? 'positive' : 'negative';
  const w1Class = changes.w1 >= 0 ? 'positive' : 'negative';

  const h1Sign = changes.h1 >= 0 ? '+' : '';
  const d1Sign = changes.d1 >= 0 ? '+' : '';
  const w1Sign = changes.w1 >= 0 ? '+' : '';

  // Per-outcome relative change as a percentage of this outcome's exposure.
  // `null` when exposure is 0 — division would be undefined.
  const relPct = (val) => outcome.totalExposure > 0 ? (val / outcome.totalExposure) * 100 : null;
  const fmtPct = (p) => {
    if (p == null) return '<span style="opacity:0.5;font-size:0.9em;"> / —</span>';
    const sign = p >= 0 ? '+' : '';
    return `<span style="opacity:0.65;font-size:0.9em;"> / ${sign}${p.toFixed(1)}%</span>`;
  };
  const h1PctHtml = fmtPct(relPct(changes.h1));
  const d1PctHtml = fmtPct(relPct(changes.d1));
  const w1PctHtml = fmtPct(relPct(changes.w1));

  // Build the row HTML
  let rowHtml = `<tr class="${isFirst ? 'market-first-row' : 'market-continuation-row'}">`;

  // Only include market info cells on first row (with rowspan for multi-outcome markets)
  if (isFirst) {
    const marketUrl = marketInfo.eventSlug
      ? polymarketUrl('/event/' + marketInfo.eventSlug)
      : polymarketUrl('/market/' + marketInfo.slug);

    rowHtml += `
      <td ${rowSpanCount > 1 ? `rowspan="${rowSpanCount}"` : ''} class="market-index">${marketInfo.index}</td>
      <td ${rowSpanCount > 1 ? `rowspan="${rowSpanCount}"` : ''}>
        <div class="market-cell">
          ${marketInfo.icon ? `<img src="${marketInfo.icon}" class="market-icon" alt="">` : '<div class="market-icon"></div>'}
          <a href="${marketUrl}" target="_blank" class="market-link">${marketInfo.title || 'Unknown Market'}</a>
        </div>
      </td>
    `;
  }

  rowHtml += `
    <td><span class="${outcomeClass}">${outcome.outcome || '-'}</span></td>
    ${isFirst ? `<td ${rowSpanCount > 1 ? `rowspan="${rowSpanCount}"` : ''} class="expiration-date">${formatExpirationDate(marketInfo.endDate)}</td>` : ''}
    <td>${entryHtml}</td>
    <td>${traderCountHtml}</td>
    <td class="exposure-cell">${formatExposureWithShares(outcome.totalExposure, getPositionShares(outcome))}</td>
    <td>${allocPct.toFixed(2)}%</td>
    <td class="tooltip ${h1Class}">
      ${h1Sign}${formatUSD(changes.h1)}${h1PctHtml}
      ${changes.h1Details.length > 0 ? `<span class="tooltip-text">${buildChangeTooltip(changes.h1Details)}</span>` : ''}
    </td>
    <td class="tooltip ${d1Class}">
      ${d1Sign}${formatUSD(changes.d1)}${d1PctHtml}
      ${changes.d1Details.length > 0 ? `<span class="tooltip-text">${buildChangeTooltip(changes.d1Details)}</span>` : ''}
    </td>
    <td class="tooltip ${w1Class}">
      ${w1Sign}${formatUSD(changes.w1)}${w1PctHtml}
      ${changes.w1Details.length > 0 ? `<span class="tooltip-text">${buildChangeTooltip(changes.w1Details)}</span>` : ''}
    </td>
    <td class="recent-changes-cell">
      ${outcome.conditionId ? `<button type="button" class="event-link-btn" onclick="showEventChanges('${outcome.conditionId}')" title="Show every trader buying or selling this market in Recent Changes" aria-label="Show recent changes for this market">↗</button>` : ''}
    </td>
  </tr>`;

  return rowHtml;
}

function portfolioTheadHTML() {
  return `
    <tr>
      <th>#</th>
      <th class="sortable" onclick="handlePortfolioSort('title')">Market${getSortIndicator('title')}</th>
      <th>Side</th>
      <th class="sortable" onclick="handlePortfolioSort('endDate')">Expiration${getSortIndicator('endDate')}</th>
      <th>Avg Entry</th>
      <th class="sortable tooltip-header" onclick="handlePortfolioSort('traderCount')" title="Traders currently holding this outcome. (+entered/&minus;exited) over the last 24h.">Traders${getSortIndicator('traderCount')}<span class="header-info">&plusmn;24h in/out</span></th>
      <th class="sortable" onclick="handlePortfolioSort('totalExposure')">Exposure, $ / shares${getSortIndicator('totalExposure')}</th>
      <th>% Alloc</th>
      <th class="sortable tooltip-header" onclick="handlePortfolioSort('change1h')">1h Change${getSortIndicator('change1h')}<span class="header-info">last hour</span></th>
      <th class="sortable tooltip-header" onclick="handlePortfolioSort('change1d')">24h Change${getSortIndicator('change1d')}<span class="header-info">1h&ndash;24h ago</span></th>
      <th class="sortable tooltip-header" onclick="handlePortfolioSort('change1w')">1w Change${getSortIndicator('change1w')}<span class="header-info">1&ndash;7 days ago</span></th>
      <th class="recent-changes-col"><span class="recent-changes-th" title="Recent changes">${EYE_ICON}</span></th>
    </tr>
  `;
}

/**
 * Render `positions` (a subset of aggregatedPortfolio.positions) as a portfolio-style
 * table inside `theadEl`/`tbodyEl`. Used by both the main Portfolio view and the
 * Recent Changes Aggregate view.
 */
function renderPositionsAsPortfolioStyle(positions, theadEl, tbodyEl, totalExposureOverride) {
  theadEl?.closest('table')?.classList.add('portfolio-style-table');
  if (theadEl) theadEl.innerHTML = portfolioTheadHTML();

  if (!positions || positions.length === 0) {
    if (tbodyEl) tbodyEl.innerHTML = '<tr><td colspan="12" class="loading">No positions match filters</td></tr>';
    return;
  }

  for (const pos of positions) {
    const changes = calculatePositionChanges(pos.conditionId, pos.outcomeIndex);
    pos._change1h = changes.h1;
    pos._change1d = changes.d1;
    pos._change1w = changes.w1;
  }

  const groupedMarkets = groupPositionsByMarket(positions);
  if (groupedMarkets.length === 0) {
    tbodyEl.innerHTML = '<tr><td colspan="12" class="loading">No positions found</td></tr>';
    return;
  }

  for (const m of groupedMarkets) {
    m._change1hPct = m.totalExposure > 0 ? (m._change1h / m.totalExposure) * 100 : null;
    m._change1dPct = m.totalExposure > 0 ? (m._change1d / m.totalExposure) * 100 : null;
    m._change1wPct = m.totalExposure > 0 ? (m._change1w / m.totalExposure) * 100 : null;
  }

  // Stable rank by exposure — independent of the user's current sort.
  [...groupedMarkets]
    .sort((a, b) => (b.totalExposure || 0) - (a.totalExposure || 0))
    .forEach((m, i) => { m._exposureRank = i + 1; });

  const sortedMarkets = sortPositions(groupedMarkets);
  const totalExposure = totalExposureOverride
    ?? sortedMarkets.reduce((sum, m) => sum + (m.totalExposure || 0), 0);

  const html = stackEvents !== 'off'
    ? renderStackedEvents(sortedMarkets, totalExposure)
    : sortedMarkets.map((m) => renderMarketRows(m, totalExposure)).join('');

  tbodyEl.innerHTML = html;
}

/**
 * Render one grouped market (its Yes/No outcome rows) as portfolio table rows.
 * `indexOverride` blanks or replaces the leading "#" cell — used in event-stack
 * mode where the rank lives on the event header instead of each market.
 */
function renderMarketRows(market, totalExposure, indexOverride) {
  const marketInfo = {
    index: indexOverride !== undefined ? indexOverride : market._exposureRank,
    title: market.title,
    slug: market.slug,
    icon: market.icon,
    eventSlug: market.eventSlug,
    endDate: market.endDate
  };

  return market.outcomes
    .map((outcome, outcomeIdx) =>
      renderOutcomeRow(
        outcome,
        totalExposure,
        outcomeIdx === 0,
        market.outcomes.length,
        marketInfo
      )
    )
    .join('');
}

/**
 * Event-stack render: collapse markets that share an event into one section.
 *
 * `sortedMarkets` is already globally sorted, so the first market seen for an
 * event is its strongest by the active sort. Grouping in first-seen order thus
 * ranks events by their biggest single market ("biggest allocation of one
 * market inside the event") while still honouring whatever column is sorted.
 * Inside a section the markets keep that same sorted order, so the real
 * allocations within a single event are visible side by side.
 */
function renderStackedEvents(sortedMarkets, totalExposure) {
  const order = [];
  const groups = new Map();
  for (const m of sortedMarkets) {
    // Markets without an eventSlug are their own singleton "event".
    const key = m.eventSlug ? 'e:' + m.eventSlug : 'c:' + m.conditionId;
    if (!groups.has(key)) {
      groups.set(key, []);
      order.push(key);
    }
    groups.get(key).push(m);
  }

  let html = '';
  let eventRank = 0;
  for (const key of order) {
    const markets = groups.get(key);
    eventRank++;

    // A lone market in an event needs no section chrome — render it as usual,
    // but renumber it into the same sequential rank stream as the sections.
    if (markets.length < 2) {
      html += renderMarketRows(markets[0], totalExposure, eventRank);
      continue;
    }

    const eventExposure = markets.reduce((s, m) => s + (m.totalExposure || 0), 0);
    const eventAllocPct = totalExposure > 0 ? (eventExposure / totalExposure) * 100 : 0;
    const eventSlug = markets[0].eventSlug;
    const eventTitle = humanizeEventTitle(eventSlug);
    const eventUrl = polymarketUrl('/event/' + eventSlug);
    const icon = markets[0].icon;
    const collapsed = isEventStackCollapsed(key);

    html += `
      <tr class="event-stack-header${collapsed ? ' collapsed' : ''}">
        <td class="market-index">${eventRank}</td>
        <td colspan="11">
          <div class="event-stack-header-inner">
            ${icon ? `<img src="${icon}" class="market-icon" alt="">` : ''}
            <a href="${eventUrl}" target="_blank" class="market-link event-stack-title">${eventTitle}</a>
            <span class="event-stack-meta">${markets.length} markets</span>
            <button type="button" class="event-fold-btn${collapsed ? ' collapsed' : ''}"
              onclick="toggleEventStack('${key.replace(/'/g, "\\'")}')"
              aria-expanded="${collapsed ? 'false' : 'true'}"
              aria-label="${collapsed ? 'Show' : 'Hide'} this event's markets"
              title="${collapsed ? 'Show' : 'Hide'} this event's ${markets.length} markets">${CHEVRON_ICON}</button>
            <span class="event-stack-meta event-stack-exposure">${formatUSD(eventExposure)} &middot; ${eventAllocPct.toFixed(2)}%</span>
          </div>
        </td>
      </tr>
    `;

    // Folded sections show only the header; the rows are omitted entirely.
    if (collapsed) continue;

    // Markets inside the section drop their own "#"; the event header owns it.
    for (const m of markets) {
      html += renderMarketRows(m, totalExposure, '');
    }
  }
  return html;
}

/**
 * Turn an event slug into a readable title, e.g.
 * "democratic-presidential-nominee-2028" → "Democratic Presidential Nominee 2028".
 * Positions carry no explicit event title, so this is derived client-side.
 */
function humanizeEventTitle(slug) {
  if (!slug) return 'Event';
  return slug
    .split('-')
    .map((w) => (w ? w.charAt(0).toUpperCase() + w.slice(1) : w))
    .join(' ');
}

/**
 * Main portfolio table — wraps the shared renderer with the full position set.
 */
function renderPortfolioTable() {
  const tbody = document.getElementById('portfolio-tbody');
  const thead = document.getElementById('portfolio-thead');
  if (!aggregatedPortfolio?.positions) {
    if (tbody) tbody.innerHTML = '<tr><td colspan="12" class="loading">Loading...</td></tr>';
    updateBalancedFilterButton();
    updateStackEventsButton();
    return;
  }
  const positions = filterByOddsRange(filterBalancedPositions(aggregatedPortfolio.positions));
  renderPositionsAsPortfolioStyle(
    positions,
    thead,
    tbody,
    aggregatedPortfolio.summary?.totalExposure
  );
  updateBalancedFilterButton();
  updateStackEventsButton();
}

function changesTheadHTML() {
  return `
    <tr>
      <th>Time</th>
      <th>Trader</th>
      <th>Market</th>
      <th>Side</th>
      <th>Avg Entry</th>
      <th>Avg Exit</th>
      <th>Action</th>
      <th>Delta</th>
      <th>Size</th>
    </tr>
  `;
}

/**
 * Render changes table. In Aggregate mode, the filtered subset is rendered
 * as a portfolio-style aggregated view instead of a flat list of changes.
 */
function renderChangesTable(deltaFilter = 0, timeFilter = 'all') {
  const table = document.getElementById('changes-table');
  const tbody = document.getElementById('changes-tbody');
  const thead = table?.querySelector('thead');

  updateEventFilterBar();

  if (!recentChanges?.changes) {
    tbody.innerHTML = '<tr><td colspan="9" class="loading">Loading...</td></tr>';
    return;
  }

  const now = Date.now() / 1000;
  const timeThresholds = {
    '1h': now - 3600,
    '6h': now - 6 * 3600,
    '24h': now - 24 * 3600,
    '7d': now - 7 * 24 * 3600,
    'all': 0
  };

  const changes = recentChanges.changes.filter(c => {
    if (changesEventFilter && c.conditionId !== changesEventFilter) return false;
    if (Math.abs(c.delta) < deltaFilter) return false;
    if (timeFilter !== 'all' && c.timestamp < timeThresholds[timeFilter]) return false;
    return true;
  });

  if (changesAggregateMode) {
    // When scoped to a single market, Aggregate collapses the flat list into one
    // row per trader (and side), netting their buys and sells for that market.
    if (changesEventFilter) {
      renderTraderAggregate(changes, thead, tbody);
      return;
    }
    // Otherwise match whole markets, not single sides, so YES/NO outcomes stay
    // stacked together exactly like the Portfolio table.
    const matchedConditionIds = new Set(changes.map(c => c.conditionId).filter(Boolean));
    const subset = (aggregatedPortfolio?.positions || []).filter(p =>
      matchedConditionIds.has(p.conditionId)
    );
    renderPositionsAsPortfolioStyle(subset, thead, tbody);
    return;
  }

  table?.classList.remove('portfolio-style-table');
  // Restore the changes-list header in case the previous render was an aggregate.
  if (thead) thead.innerHTML = changesTheadHTML();

  if (changes.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" class="loading">No changes match filters</td></tr>';
    return;
  }

  // The feed can hold ~24h of changes (up to 20k). Render only the first slice
  // as DOM rows so the table stays responsive; the filters above narrow it.
  const MAX_CHANGE_ROWS = 1000;
  const shown = changes.slice(0, MAX_CHANGE_ROWS);
  const truncatedNote = changes.length > MAX_CHANGE_ROWS
    ? `<tr><td colspan="9" class="loading">Showing first ${MAX_CHANGE_ROWS.toLocaleString()} of ${changes.length.toLocaleString()} changes — narrow with the filters above.</td></tr>`
    : '';

  tbody.innerHTML = shown.map(c => {
    const marketUrl = c.eventSlug
      ? polymarketUrl('/event/' + c.eventSlug)
      : polymarketUrl('/market/' + c.marketSlug);

    const actionClass = c.action === 'increased' ? 'action-increased' : 'action-decreased';
    const outcomeClass = c.outcome === 'Yes' ? 'outcome-yes' : 'outcome-no';

    // Entry/exit are the trade's own execution price — a buy fills the entry
    // column, a sell fills the exit column. Splits, merges and redeems carry
    // no trade price (they only move the held amount), so both stay blank.
    const avgEntryDisplay = (c.action === 'increased' && c.price) ? formatCents(c.price) : '-';
    const avgExitDisplay = (c.action === 'decreased' && c.price) ? formatCents(c.price) : '-';

    // Format delta with trade price in brackets
    const tradePrice = c.price ? formatCents(c.price) : '';
    const deltaDisplay = `${c.delta >= 0 ? '+' : ''}${formatUSD(c.delta)}${tradePrice ? ` (${tradePrice})` : ''}`;

    return `
      <tr>
        <td>${formatRelativeTime(c.timestamp)}</td>
        <td>
          <a href="${polymarketUrl('/profile/' + c.traderAddress)}" target="_blank" class="market-link trader-link">${c.trader}</a>
        </td>
        <td>
          <a href="${marketUrl}" target="_blank" class="market-link">${c.market}</a>
        </td>
        <td><span class="${outcomeClass}">${c.outcome || '-'}</span></td>
        <td>${avgEntryDisplay}</td>
        <td>${avgExitDisplay}</td>
        <td class="${actionClass}">${c.action}</td>
        <td class="${c.delta >= 0 ? 'positive' : 'negative'}">${deltaDisplay}</td>
        <td>${formatUSD(Math.abs(c.size))}</td>
      </tr>
    `;
  }).join('') + truncatedNote;
}

/**
 * Collapse a list of changes into one entry per trader + side, netting the
 * USD delta and share size and counting the number of trades.
 */
function aggregateChangesByTrader(changes) {
  const groups = new Map();

  for (const c of changes) {
    const key = `${(c.traderAddress || c.trader || '').toLowerCase()}|${c.outcomeIndex}`;
    let g = groups.get(key);
    if (!g) {
      g = {
        trader: c.trader,
        traderAddress: c.traderAddress,
        conditionId: c.conditionId,
        outcome: c.outcome,
        outcomeIndex: c.outcomeIndex,
        eventSlug: c.eventSlug,
        marketSlug: c.marketSlug,
        netDelta: 0,
        netSize: 0,
        // Avg entry/exit are volume-weighted over real BUY / SELL trades only.
        // Splits, merges and redeems move the held amount (netSize) but must
        // not dilute these price averages.
        buyUsd: 0, buySize: 0,
        sellUsd: 0, sellSize: 0,
        trades: 0,
        lastTimestamp: 0
      };
      groups.set(key, g);
    }
    const size = Math.abs(parseFloat(c.size) || 0);
    const delta = c.delta || 0;
    g.netDelta += delta;
    g.netSize += (delta >= 0 ? size : -size);
    if (c.action === 'increased') { g.buyUsd += Math.abs(delta); g.buySize += size; }
    else if (c.action === 'decreased') { g.sellUsd += Math.abs(delta); g.sellSize += size; }
    g.trades += 1;
    if ((c.timestamp || 0) > g.lastTimestamp) g.lastTimestamp = c.timestamp || 0;
  }

  for (const g of groups.values()) {
    g.avgEntry = g.buySize > 0 ? g.buyUsd / g.buySize : null;
    g.avgExit = g.sellSize > 0 ? g.sellUsd / g.sellSize : null;
  }

  return Array.from(groups.values()).sort((a, b) => Math.abs(b.netDelta) - Math.abs(a.netDelta));
}

/**
 * Render the single-market Aggregate view: one row per trader (and side) with
 * their net buying/selling for the filtered market.
 */
function renderTraderAggregate(changes, thead, tbody) {
  const table = thead?.closest('table') || document.getElementById('changes-table');
  table?.classList.remove('portfolio-style-table');

  if (thead) {
    thead.innerHTML = `
      <tr>
        <th>Trader</th>
        <th>Side</th>
        <th>Avg Entry</th>
        <th>Avg Exit</th>
        <th>Net Action</th>
        <th>Net Delta</th>
        <th>Net Size</th>
        <th>Trades</th>
      </tr>
    `;
  }

  const rows = aggregateChangesByTrader(changes);
  if (rows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="8" class="loading">No changes match filters</td></tr>';
    return;
  }

  tbody.innerHTML = rows.map(r => {
    const outcomeClass = r.outcome === 'Yes' ? 'outcome-yes' : 'outcome-no';
    const isBuy = r.netDelta >= 0;
    const actionLabel = isBuy ? 'bought' : 'sold';
    const actionClass = isBuy ? 'action-increased' : 'action-decreased';
    const deltaClass = isBuy ? 'positive' : 'negative';
    const deltaSign = isBuy ? '+' : '';

    // Entry = VWAP of buys, exit = VWAP of sells (splits/merges excluded).
    const avgEntryDisplay = r.avgEntry ? formatCents(r.avgEntry) : '-';
    const avgExitDisplay = r.avgExit ? formatCents(r.avgExit) : '-';

    return `
      <tr>
        <td>
          <a href="${polymarketUrl('/profile/' + r.traderAddress)}" target="_blank" class="market-link trader-link">${r.trader}</a>
        </td>
        <td><span class="${outcomeClass}">${r.outcome || '-'}</span></td>
        <td>${avgEntryDisplay}</td>
        <td>${avgExitDisplay}</td>
        <td class="${actionClass}">${actionLabel}</td>
        <td class="${deltaClass}">${deltaSign}${formatUSD(r.netDelta)}</td>
        <td>${formatShares(r.netSize)} shares</td>
        <td>${r.trades}</td>
      </tr>
    `;
  }).join('');
}

