/**
 * Track user activity
 */
function trackActivity() {
  lastActivityTime = Date.now();
}

/**
 * Check for inactivity and show refresh prompt
 */
function checkInactivity() {
  const now = Date.now();
  const inactive = now - lastActivityTime > INACTIVITY_TIMEOUT;
  const statusDot = document.querySelector('.status-dot');

  if (inactive && statusDot) {
    statusDot.classList.add('stale');
  }
}

/**
 * Refresh data
 */
async function refreshData() {
  const btn = document.getElementById('refresh-btn');
  btn?.classList.add('loading');

  try {
    await loadData();
    lastActivityTime = Date.now();
  } finally {
    btn?.classList.remove('loading');
  }
}

/**
 * Initialize refresh button
 */
function initRefresh() {
  const btn = document.getElementById('refresh-btn');
  btn?.addEventListener('click', refreshData);

  // Track activity
  ['mousemove', 'keypress', 'click', 'scroll', 'touchstart'].forEach(event => {
    document.addEventListener(event, trackActivity, { passive: true });
  });

  // Check inactivity every minute
  setInterval(checkInactivity, 60000);
}

// ============================================================
// UPDATE DB BUTTON (manual refresh via Cloudflare Worker)
// ============================================================

/**
 * Ask the pmw-trigger worker to dispatch a fresh data run, then poll
 * metadata.json until last_updated changes and reload the dashboard.
 * The worker rate-limits manual triggers, so the button surfaces the
 * cooldown when one is active.
 */
async function triggerUpdate() {
  const btn = document.getElementById('update-btn');
  if (!btn || btn.disabled) return;

  btn.disabled = true;
  btn.textContent = 'Triggering...';
  btn.className = 'update-btn';

  try {
    const res = await fetch(`${WORKER_URL}/trigger-update?repo=polymarket`, { method: 'POST' });
    const data = await res.json();

    if (data.status === 'triggered') {
      // Poll metadata.json every 5s until last_updated changes, then reload
      const knownTimestamp = metadata?.last_updated || null;
      let elapsed = 0;
      btn.className = 'update-btn triggered';
      btn.textContent = 'Updating…';

      updatePollTimer = setInterval(async () => {
        elapsed += 5;
        btn.textContent = `Updating… ${elapsed}s`;
        try {
          const fresh = await fetch(`${DATA_BASE}/metadata.json`, { cache: 'no-cache' });
          const meta = await fresh.json();
          if (meta.last_updated !== knownTimestamp) {
            clearInterval(updatePollTimer);
            await loadData();
            btn.textContent = 'Updated!';
            btn.className = 'update-btn triggered';
            setTimeout(() => {
              btn.textContent = 'Update DB';
              btn.disabled = false;
              btn.className = 'update-btn';
            }, 3000);
          }
        } catch (_) { /* ignore fetch errors during poll */ }

        // Timeout after 3 minutes
        if (elapsed >= 180) {
          clearInterval(updatePollTimer);
          btn.textContent = 'Update DB';
          btn.disabled = false;
          btn.className = 'update-btn';
        }
      }, 5000);

    } else if (data.status === 'rate_limited') {
      let secs = data.cooldown_remaining_sec || 300;
      btn.className = 'update-btn';
      btn.textContent = `Wait ${secs}s`;
      const t = setInterval(() => {
        secs--;
        btn.textContent = `Wait ${secs}s`;
        if (secs <= 0) {
          clearInterval(t);
          btn.textContent = 'Update DB';
          btn.disabled = false;
        }
      }, 1000);

    } else {
      btn.textContent = 'Error — retry?';
      btn.disabled = false;
      setTimeout(() => { btn.textContent = 'Update DB'; btn.className = 'update-btn'; }, 4000);
    }
  } catch (err) {
    console.error('triggerUpdate error:', err);
    btn.textContent = 'Network error';
    btn.disabled = false;
    setTimeout(() => { btn.textContent = 'Update DB'; btn.className = 'update-btn'; }, 4000);
  }
}

/**
 * Initialize the manual Update DB button (no-op when the element is absent)
 */
function initUpdateTrigger() {
  document.getElementById('update-btn')?.addEventListener('click', triggerUpdate);
}

// ============================================================
// DATA LOADING
// ============================================================

/**
 * Load all data.
 *
 * metadata.json is always fetched fresh (no-cache). If it carries a snapshot
 * id that matches the data we already rendered, the big files are unchanged
 * and only the last-updated display is refreshed. Otherwise the big files are
 * fetched from their immutable per-snapshot URLs (or the flat legacy URLs
 * when no snapshot is set). Concurrent calls no-op via the isLoading guard.
 */
async function loadData() {
  if (isLoading) return;
  isLoading = true;

  try {
    const metaResponse = await fetch(`${DATA_BASE}/metadata.json`, { cache: 'no-cache' });
    if (!metaResponse.ok) {
      throw new Error('Failed to fetch metadata.json');
    }
    const freshMetadata = await metaResponse.json();
    const snapshot = freshMetadata.snapshot ?? null;

    // Same snapshot as the one on screen — data unchanged, skip the big files.
    if (snapshot && snapshot === loadedSnapshot) {
      metadata = freshMetadata;
      updateLastUpdated();
      return;
    }

    [traderPortfolios, aggregatedPortfolio, recentChanges] = await Promise.all([
      fetchSnapshotJSON('trader_portfolios.json', snapshot),
      fetchSnapshotJSON('aggregated_portfolio.json', snapshot),
      fetchSnapshotJSON('recent_changes.json', snapshot)
    ]);
    metadata = freshMetadata;
    loadedSnapshot = snapshot;

    mergeCanary();              // re-inject after each fresh trader_portfolios load

    updateLastUpdated();
    updateTrackedTradersTitle();
    renderTradersTable();
    renderPortfolioSummary();
    renderPortfolioTable();
    renderChangesTable();
  } catch (error) {
    console.error('Failed to load data:', error);
    document.getElementById('traders-tbody').innerHTML =
      '<tr><td colspan="7" class="loading">Failed to load data. Run the fetch script first.</td></tr>';
  } finally {
    isLoading = false;
  }
}

